265→/// Build [`MockParam`]s from dependencies and their resolved mock configs.
266→///
267→/// Filters out dependencies whose category is [`IoCategory::PureUtility`]
268→/// unless a matching config explicitly overrides them. Dependencies with
269→/// a matching config get [`ValueSource::UserOverride`]; those without get
270→/// [`ValueSource::AutoGenerated`].
271→pub fn build_mock_params(
272→    deps: &[ExternalDependency],
273→    configs: &[MockConfig],
274→) -> Vec<MockParam> {
275→    let config_by_symbol: HashMap<&str, &MockConfig> = configs
276→        .iter()
277→        .map(|c| (c.symbol.as_str(), c))
278→        .collect();
279→
280→    let mut result = Vec::new();
281→
282→    for dep in deps {
283→        let category = classify_dependency(dep);
284→        let has_config = config_by_symbol.contains_key(dep.symbol.as_str());
285→
286→        // Pure utilities are passthrough unless explicitly configured
287→        if category == IoCategory::PureUtility && !has_config {
288→            continue;
289→        }
290→
291→        let value_source = if has_config {
292→            ValueSource::UserOverride
293→        } else {
294→            ValueSource::AutoGenerated
295→        };
296→
297→        result.push(MockParam {
298→            symbol: dep.symbol.clone(),
299→            return_type: dep.return_type.clone(),
300→            category,
301→            call_count_estimate: dep.call_sites.len() as u32,
302→            value_source,
303→        });
304→    }
305→
306→    result
307→}
